```ts
import { setup, sendTo, assign } from 'xstate';

type TimerEvent =
  | { type: 'TICK' }
  | { type: 'PAUSE' }
  | { type: 'RESUME' }
  | { type: 'DONE' };

const timerChild = setup({
  types: {
    context: {} as { remaining: number },
    events: {} as TimerEvent,
  },
}).createMachine({
  id: 'timer',
  initial: 'running',
  context: { remaining: 10 },
  states: {
    running: {
      after: {
        1000: [
          {
            guard: ({ context }) => context.remaining > 1,
            target: 'running',
            actions: assign({ remaining: ({ context }) => context.remaining - 1 }),
            reenter: true,
          },
          { target: 'finished' },
        ],
      },
      on: { PAUSE: 'paused' },
    },
    paused: {
      on: { RESUME: 'running' },
    },
    finished: {
      entry: sendTo(({ self }) => self._parent!, { type: 'DONE' }),
      type: 'final',
    },
  },
});

type ParentEvent =
  | { type: 'PAUSE' }
  | { type: 'RESUME' }
  | { type: 'DONE' };

export const parentMachine = setup({
  types: {
    context: {} as { finished: boolean },
    events: {} as ParentEvent,
  },
  actors: { timerChild },
}).createMachine({
  id: 'parent',
  initial: 'running',
  context: { finished: false },
  invoke: {
    id: 'timer',
    src: 'timerChild',
  },
  states: {
    running: {
      on: {
        PAUSE: { actions: sendTo('timer', { type: 'PAUSE' }) },
        RESUME: { actions: sendTo('timer', { type: 'RESUME' }) },
        DONE: {
          target: 'completed',
          actions: assign({ finished: true }),
        },
      },
    },
    completed: { type: 'final' },
  },
});
```

Convert this XState v4 machine to v5 using setup().createMachine. The child machine should send SAVED back to the parent when it finishes saving.

```js
const childMachine = Machine({
  id: 'saver',
  initial: 'saving',
  states: {
    saving: { on: { DONE: 'saved' } },
    saved: { entry: sendParent('SAVED'), type: 'final' }
  }
});
const parentMachine = Machine({
  id: 'parent',
  initial: 'idle',
  states: {
    idle: { on: { START: 'working' } },
    working: {
      invoke: { id: 'saver', src: childMachine },
      on: { SAVED: 'done', TRIGGER_DONE: { actions: send('DONE', { to: 'saver' }) } }
    },
    done: { type: 'final' }
  }
});
