import { setup, sendTo } from 'xstate';

type WorkerEvent = { type: 'DO' } | { type: 'STOP' };

const worker = setup({
  types: { events: {} as WorkerEvent },
}).createMachine({
  id: 'worker',
  initial: 'idle',
  states: {
    idle: {
      on: {
        DO: 'working',
        STOP: 'cancelled',
      },
    },
    working: {
      on: { STOP: 'cancelled' },
      after: { 1000: 'done' },
    },
    done: {
      entry: sendTo(({ self }) => self._parent!, { type: 'CHILD_DONE' }),
      type: 'final',
    },
    cancelled: {
      entry: sendTo(({ self }) => self._parent!, { type: 'CHILD_CANCELLED' }),
      type: 'final',
    },
  },
});

type ParentEvent =
  | { type: 'GO' }
  | { type: 'CANCEL' }
  | { type: 'CHILD_DONE' }
  | { type: 'CHILD_CANCELLED' };

export const parent = setup({
  types: { events: {} as ParentEvent },
  actors: { worker },
}).createMachine({
  id: 'parent',
  invoke: { id: 'w', src: 'worker' },
  initial: 'run',
  states: {
    run: {
      on: {
        GO: { actions: sendTo('w', { type: 'DO' }) },
        CANCEL: {
          target: 'cancelled',
          actions: sendTo('w', { type: 'STOP' }),
        },
        CHILD_DONE: 'done',
      },
    },
    cancelled: {
      on: { CHILD_CANCELLED: 'done' },
    },
    done: { type: 'final' },
  },
});
