In XState v5, the parent registers the child under `setup.actors` and invokes it with `invoke: { id, src }`. The parent addresses it by id with `sendTo('id', event)`; the child talks back with `sendTo(({ self }) => self._parent!, event)`. Both directions are typed through each machine's `setup.types.events`, so message shapes are enforced at the callsite.

```ts
import { setup, sendTo, assign } from 'xstate';

type SaverEvent = { type: 'SAVE'; payload: string };

const formSaver = setup({
  types: {
    context: {} as { lastSaved: string },
    events: {} as SaverEvent,
  },
}).createMachine({
  id: 'saver',
  initial: 'idle',
  context: { lastSaved: '' },
  states: {
    idle: {
      on: {
        SAVE: {
          target: 'saving',
          actions: assign({ lastSaved: ({ event }) => event.payload }),
        },
      },
    },
    saving: {
      after: {
        300: {
          target: 'idle',
          actions: sendTo(({ self }) => self._parent!, ({ context }) => ({
            type: 'SAVED' as const,
            at: context.lastSaved,
          })),
        },
      },
    },
  },
});

type ParentEvent =
  | { type: 'SUBMIT'; text: string }
  | { type: 'SAVED'; at: string };

export const formHost = setup({
  types: {
    context: {} as { history: string[] },
    events: {} as ParentEvent,
  },
  actors: { formSaver },
}).createMachine({
  id: 'host',
  context: { history: [] },
  invoke: { id: 'saver', src: 'formSaver' },
  on: {
    SUBMIT: {
      actions: sendTo('saver', ({ event }) => ({
        type: 'SAVE' as const,
        payload: event.text,
      })),
    },
    SAVED: {
      actions: assign({
        history: ({ context, event }) => [...context.history, event.at],
      }),
    },
  },
});
```

