A child machine asks its parent for data by sending a request event via `sendTo(({ self }) => self._parent, ...)`. The parent handles that event by reading its own context and replying to the child by id with `sendTo('childId', ...)`. Both messages flow through each machine's typed event union, so the shapes are enforced end-to-end.

```ts
import { setup, sendTo, assign } from 'xstate';

type ChildEvent =
  | { type: 'START' }
  | { type: 'CONFIG'; apiUrl: string };

const configurable = setup({
  types: {
    context: {} as { apiUrl: string },
    events: {} as ChildEvent,
  },
}).createMachine({
  id: 'configurable',
  initial: 'starting',
  context: { apiUrl: '' },
  states: {
    starting: {
      entry: sendTo(({ self }) => self._parent!, { type: 'REQUEST_CONFIG' as const }),
      on: {
        CONFIG: {
          target: 'ready',
          actions: assign({ apiUrl: ({ event }) => event.apiUrl }),
        },
      },
    },
    ready: {
      type: 'final',
    },
  },
});

type ParentEvent = { type: 'REQUEST_CONFIG' };

export const host = setup({
  types: {
    context: {} as { apiUrl: string },
    events: {} as ParentEvent,
  },
  actors: { configurable },
}).createMachine({
  id: 'host',
  context: { apiUrl: 'https://api.example.com' },
  invoke: { id: 'child', src: 'configurable' },
  on: {
    REQUEST_CONFIG: {
      actions: sendTo('child', ({ context }) => ({
        type: 'CONFIG' as const,
        apiUrl: context.apiUrl,
      })),
    },
  },
});
```

