`raise(event)` in v5 schedules an event to be processed by the same actor in its next microstep. Because it lands in the actor's own queue, any state matching that event's `on` handler will process it — including the state the action just entered. It is commonly used to chain internal transitions without exposing intermediate events externally.

```ts
import { setup, raise, assign, fromPromise } from 'xstate';

type Event =
  | { type: 'FETCH' }
  | { type: 'RETRY' };

const loader = fromPromise<string, void>(async () => {
  const res = await fetch('/api/data');
  if (!res.ok) throw new Error('HTTP ' + res.status);
  return res.text();
});

export const retryMachine = setup({
  types: {
    context: {} as { data?: string; attempts: number },
    events: {} as Event,
  },
  actors: { loader },
}).createMachine({
  id: 'retry',
  initial: 'idle',
  context: { attempts: 0 },
  states: {
    idle: {
      on: { FETCH: 'loading' },
    },
    loading: {
      entry: assign({ attempts: ({ context }) => context.attempts + 1 }),
      invoke: {
        src: 'loader',
        onDone: {
          target: 'done',
          actions: assign({ data: ({ event }) => event.output }),
        },
        onError: [
          {
            guard: ({ context }) => context.attempts < 3,
            actions: raise({ type: 'RETRY' }),
          },
          { target: 'failed' },
        ],
      },
      on: { RETRY: 'loading' },
    },
    done: { type: 'final' },
    failed: { type: 'final' },
  },
});
```

