  id: 'thermostat',
  initial: 'idle',
  context: { temp: 20, target: 22 },
  states: {
    idle: {
      on: {
        HEAT: { target: 'heating', cond: 'needsHeat' },
        COOL: { target: 'cooling', cond: 'needsCool' }
      }
    },
    heating: { on: { STOP: { target: 'idle', actions: 'logStop' } } },
    cooling: { on: { STOP: { target: 'idle', actions: 'logStop' } } }
  }
}, {
  actions: { logStop: (ctx, ev) => console.log('stopped', ev.type) },
  guards: {
    needsHeat: (ctx) => ctx.temp < ctx.target,
    needsCool: (ctx) => ctx.temp > ctx.target
  }
});
