```ts
import { setup, assign } from 'xstate';

type Event =
  | { type: 'SWIPE'; cardId: string }
  | { type: 'OPEN' }
  | { type: 'CLOSE' };

export const door = setup({
  types: {
    context: {} as {
      authorized: readonly string[];
      lastCard: string | null;
      attempts: number;
    },
    events: {} as Event,
  },
  actions: {
    rememberCard: assign({
      lastCard: ({ context, event }) =>
        event.type === 'SWIPE' ? event.cardId : context.lastCard,
    }),
    bumpAttempts: assign({
      attempts: ({ context }) => context.attempts + 1,
    }),
    resetAttempts: assign({ attempts: 0 }),
  },
  guards: {
    isAuthorized: ({ context, event }) =>
      event.type === 'SWIPE' && context.authorized.includes(event.cardId),
  },
}).createMachine({
  id: 'door',
  initial: 'locked',
  context: { authorized: ['A1', 'B2'], lastCard: null, attempts: 0 },
  states: {
    locked: {
      on: {
        SWIPE: [
          {
            guard: 'isAuthorized',
            target: 'unlocked',
            actions: ['rememberCard', 'resetAttempts'],
          },
          {
            actions: ['rememberCard', 'bumpAttempts'],
          },
        ],
      },
    },
    unlocked: {
      on: {
        OPEN: 'open',
        CLOSE: 'locked',
      },
    },
    open: {
      on: { CLOSE: 'locked' },
    },
  },
});
